const hamburger=document.querySelector('.hamburger');const navLinks=document.querySelector('.nav-links');hamburger.addEventListener('click',()=>{hamburger.classList.toggle('active');navLinks.classList.toggle('active');});navLinks.querySelectorAll('a').forEach(link=>{link.addEventListener('click',()=>{hamburger.classList.remove('active');navLinks.classList.remove('active');});});const sections=document.querySelectorAll('section[id]');window.addEventListener('scroll',()=>{const scrollY=window.scrollY+100;sections.forEach(section=>{const top=section.offsetTop;const height=section.offsetHeight;const id=section.getAttribute('id');const link=document.querySelector(`.nav-links a[href="#${id}"]`);if(link){if(scrollY>=top&&scrollY<top+height){link.classList.add('active');}else{link.classList.remove('active');}}});});const fadeElements=document.querySelectorAll('.fade-in');const fadeObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add('visible');fadeObserver.unobserve(entry.target);}});},{threshold:0.1,rootMargin:'0px 0px -40px 0px'});fadeElements.forEach(el=>fadeObserver.observe(el));document.querySelectorAll('.video-wrapper').forEach(wrapper=>{const iframe=wrapper.querySelector('iframe');if(iframe&&iframe.dataset.src){const videoObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){iframe.src=iframe.dataset.src;iframe.removeAttribute('data-src');videoObserver.unobserve(wrapper);}});},{rootMargin:'200px'});videoObserver.observe(wrapper);}});const lightbox=document.getElementById('lightbox');const lightboxImg=lightbox?.querySelector('img');const lightboxCaption=lightbox?.querySelector('.lightbox-caption');const galleryItems=document.querySelectorAll('.gallery-item');let currentGalleryIndex=0;let filteredItems=[...galleryItems];function openLightbox(index){currentGalleryIndex=index;const item=filteredItems[index];if(!item)return;const img=item.querySelector('img');const caption=item.querySelector('.gallery-caption');lightboxImg.src=img.dataset.full||img.src;lightboxImg.alt=img.alt;lightboxCaption.textContent=caption?caption.textContent:'';lightbox.classList.add('active');document.body.style.overflow='hidden';}
function closeLightbox(){lightbox.classList.remove('active');document.body.style.overflow='';}
function navigateLightbox(dir){currentGalleryIndex=(currentGalleryIndex+dir+filteredItems.length)%filteredItems.length;openLightbox(currentGalleryIndex);}
galleryItems.forEach((item,i)=>{item.addEventListener('click',()=>{filteredItems=[...document.querySelectorAll('.gallery-item:not([style*="display: none"])')];const idx=filteredItems.indexOf(item);openLightbox(idx>=0?idx:0);});});lightbox?.querySelector('.lightbox-close')?.addEventListener('click',closeLightbox);lightbox?.querySelector('.lightbox-prev')?.addEventListener('click',()=>navigateLightbox(-1));lightbox?.querySelector('.lightbox-next')?.addEventListener('click',()=>navigateLightbox(1));lightbox?.addEventListener('click',(e)=>{if(e.target===lightbox)closeLightbox();});document.addEventListener('keydown',(e)=>{if(!lightbox?.classList.contains('active'))return;if(e.key==='Escape')closeLightbox();if(e.key==='ArrowLeft')navigateLightbox(-1);if(e.key==='ArrowRight')navigateLightbox(1);});document.querySelectorAll('.filter-btn').forEach(btn=>{btn.addEventListener('click',()=>{document.querySelectorAll('.filter-btn').forEach(b=>b.classList.remove('active'));btn.classList.add('active');const filter=btn.dataset.filter;galleryItems.forEach(item=>{if(filter==='all'||item.dataset.category===filter){item.style.display='';}else{item.style.display='none';}});filteredItems=[...document.querySelectorAll('.gallery-item:not([style*="display: none"])')];});});document.querySelectorAll('.press-card').forEach(card=>{card.addEventListener('click',()=>{const img=card.querySelector('img');const title=card.querySelector('h4');if(img&&lightboxImg){lightboxImg.src=img.src;lightboxCaption.textContent=title?title.textContent:'';lightbox.classList.add('active');document.body.style.overflow='hidden';}});});function submitContactForm(form){setTimeout(function(){form.style.display='none';document.getElementById('form-success').style.display='block';},500);}